document.addEventListener('DOMContentLoaded', function() {
    let i = 0;
    const p = document.getElementById('Colleen2');
    if (p) {
        setInterval(() => {
            p.innerText = frames[i];
            i = (i + 1) % frames.length;
        }, 83);
    } else {
        console.error('Element with id "Colleen2" not found');
    }
});
